const formula = $env.PRIORITIZATION_FORMULA || 'RICE';
const items = $input.all().map(i => {
  const d = i.json;
  const R = parseFloat(d.reach||1), I = parseFloat(d.impact||1), C = parseFloat(d.confidence||100)/100, E = parseFloat(d.effort||1);
  let score;
  if (formula === 'ICE') { score = I * C * (1/E) * 100; }
  else { score = (R * I * C) / E; } // RICE
  return { ...d, score: Math.round(score * 10) / 10, formula };
});
const ranked = items.sort((a,b) => b.score - a.score);
return ranked.map(r => ({ json: r }));

