const ranked = $('Calculate Scores').all().map(i => i.json);
let enriched;
try { enriched = JSON.parse(($input.first().json.message?.content||'[]').replace(/```json|```/g,'').trim()); if (!Array.isArray(enriched)) enriched = []; } catch { enriched = []; }
const result = ranked.map((item, i) => ({ ...item, ...(enriched[i]||{}) }));
return [{ json: { generated_at: new Date().toISOString(), formula: $env.PRIORITIZATION_FORMULA||'RICE', total: result.length, ranked_roadmap: result } }];
